import { Component, OnInit } from '@angular/core';
import { AuthService } from '../../../core/services/auth.service';
import { UserService, TeamService } from '../../../core/services/api.services';
import { ToastService } from '../../../core/services/toast.service';
import { User, Team } from '../../../core/models';

@Component({ selector: 'app-employee-list', templateUrl: './employee-list.component.html' })
export class EmployeeListComponent implements OnInit {
  users: User[] = [];
  filtered: User[] = [];
  loading = true;
  searchTerm = '';
  filterRole = '';
  filterStatus = '';
  currentPage = 1;
  pageSize = 5;

  showDelConfirm = false;
  selectedUser: User | null = null;

  constructor(public auth: AuthService, private userService: UserService, private toast: ToastService) {}

  ngOnInit(): void { this.load(); }

  load(): void {
    this.loading = true;
    // PM sees everyone; DeptHead sees their dept; TeamLead + Employee see their team only
    if (this.auth.isEmployee && !this.auth.teamId) {
      this.users = []; this.filtered = []; this.loading = false; return;
    }
    const obs = this.auth.isDeptHead ? this.userService.getByDept(this.auth.deptId)
      : (this.auth.isTeamLead || this.auth.isEmployee) ? this.userService.getByTeam(this.auth.teamId)
      : this.userService.getAll();
    obs.subscribe(r => {
      if (r.success) { this.users = r.data; this.applyFilters(); }
      this.loading = false;
    });
  }

  applyFilters(): void {
    let result = [...this.users];
    if (this.searchTerm) {
      const term = this.searchTerm.toLowerCase();
      result = result.filter(u => u.firstName.toLowerCase().includes(term) ||
        u.lastName.toLowerCase().includes(term) || u.email.toLowerCase().includes(term));
    }
    if (this.filterRole) result = result.filter(u => u.role === this.filterRole);
    if (this.filterStatus) result = result.filter(u => u.approvalStatus === this.filterStatus);
    this.filtered = result;
    this.currentPage = 1;
  }

  get paginated(): User[] {
    const start = (this.currentPage - 1) * this.pageSize;
    return this.filtered.slice(start, start + this.pageSize);
  }

  nextPage() {
    if (this.currentPage * this.pageSize < this.filtered.length) this.currentPage++;
  }

  prevPage() {
    if (this.currentPage > 1) this.currentPage--;
  }

  confirmDelete(u: User): void { this.selectedUser = u; this.showDelConfirm = true; }
  doDelete(): void {
    if (!this.selectedUser) return;
    this.userService.delete(this.selectedUser.id).subscribe({
      next: r => {
        if (r.success) {
          this.showDelConfirm = false;
          this.toast.showSuccess(`${this.selectedUser!.firstName} ${this.selectedUser!.lastName} removed successfully`);
          this.selectedUser = null;
          this.load();
        } else { this.toast.showError(r.message || 'Failed to remove user'); }
      },
      error: err => this.toast.showError(err.error?.message || 'Error removing user')
    });
  }

  openTeamModal(u: User): void {
    this.selectedUser = u;
    this.targetTeamId = u.team?.id || 0;
    this.showTeamModal = true;

    // Fetch teams for the current department (if manager)
    const deptId = u.department?.id || (this.auth.isDeptHead ? this.auth.deptId : 0);
    if (deptId) {
      this.teamService.getByDept(deptId).subscribe(r => {
        if (r.success) this.teams = r.data;
      });
    } else {
      this.teamService.getAll().subscribe(r => {
        if (r.success) this.teams = r.data;
      });
    }
  }

  doAssignTeam(): void {
    if (!this.selectedUser) return;
    this.userService.update(this.selectedUser.id, { teamId: this.targetTeamId || null }).subscribe({
      next: r => {
        if (r.success) {
          this.showTeamModal = false;
          this.toast.showSuccess(`Team updated for ${this.selectedUser!.firstName}`);
          this.selectedUser = null;
          this.load();
        } else { this.toast.showError(r.message || 'Failed to update team'); }
      },
      error: err => this.toast.showError(err.error?.message || 'Error updating team')
    });
  }

  getRoleBadge(r: string): string {
    const m: any = { PROJECT_MANAGER:'badge-purple', DEPARTMENT_HEAD:'badge-blue', TEAM_LEAD:'badge-yellow', EMPLOYEE:'badge-gray' };
    return m[r] || 'badge-gray';
  }
  getStatusBadge(s: string): string {
    const m: any = { APPROVED:'badge-green', PENDING:'badge-yellow', REJECTED:'badge-red' };
    return m[s] || 'badge-gray';
  }
  getUtilClass(u: User): string {
    const pct = u.maxCapacityHours ? ((u.allocatedHours || 0) / u.maxCapacityHours) * 100 : 0;
    return pct > 100 ? 'overload' : pct >= 70 ? 'optimal' : 'underutil';
  }
  getUtilPct(u: User): number {
    return u.maxCapacityHours ? Math.min(((u.allocatedHours || 0) / u.maxCapacityHours) * 100, 150) : 0;
  }
  formatRole(r: string): string {
    const m: any = { PROJECT_MANAGER:'Project Manager', DEPARTMENT_HEAD:'Dept Head', TEAM_LEAD:'Team Lead', EMPLOYEE:'Employee' };
    return m[r] || r;
  }
}
<div class="fade-in">
  <div class="page-header">
    <div>
      <div class="page-title">{{ auth.isDeptHead ? 'My Department' : auth.isTeamLead ? 'My Team' : 'All Employees' }}</div>
      <div class="page-subtitle">{{ filtered.length }} people</div>
    </div>
  </div>

  <div class="filter-bar">
    <div class="filter-search">
      <span class="search-icon">🔍</span>
      <input class="form-control" placeholder="Search by name or email..." [(ngModel)]="searchTerm" (ngModelChange)="applyFilters()">
    </div>
    <select class="form-control" [(ngModel)]="filterRole" (ngModelChange)="applyFilters()" style="width:160px">
      <option value="">All Roles</option>
      <option value="PROJECT_MANAGER">Project Manager</option>
      <option value="DEPARTMENT_HEAD">Dept Head</option>
      <option value="TEAM_LEAD">Team Lead</option>
      <option value="EMPLOYEE">Employee</option>
    </select>
    <select class="form-control" [(ngModel)]="filterStatus" (ngModelChange)="applyFilters()" style="width:140px">
      <option value="">All Status</option>
      <option value="APPROVED">Approved</option>
      <option value="PENDING">Pending</option>
      <option value="REJECTED">Rejected</option>
    </select>
  </div>

  <div *ngIf="loading" class="loading-wrap"><div class="spinner"></div></div>

  <div *ngIf="!loading && filtered.length === 0" class="empty-state card" style="padding:60px">
    <div class="empty-icon">◉</div>
    <div class="empty-title">No employees found</div>
  </div>

  <div *ngIf="!loading && filtered.length > 0" class="card" style="padding:0">
    <div class="table-responsive">
      <table class="data-table">
        <thead>
          <tr>
            <th>Person</th>
            <th>Role</th>
            <th>Department / Team</th>
            <th>Utilization</th>
            <th>Status</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let u of paginated" [routerLink]="['/employees', u.id]" style="cursor:pointer">
          <td>
            <div style="display:flex;align-items:center;gap:10px">
              <div class="avatar">{{ u.firstName[0] }}{{ u.lastName[0] }}</div>
              <div>
                <div style="font-weight:600">{{ u.firstName }} {{ u.lastName }}</div>
                <div style="font-size:12px;color:var(--text-muted)">{{ u.email }}</div>
              </div>
            </div>
          </td>
          <td><span class="badge" [ngClass]="getRoleBadge(u.role)">{{ formatRole(u.role) }}</span></td>
          <td>
            <div>{{ u.department?.name || '—' }}</div>
            <div style="font-size:12px;color:var(--text-muted)">{{ u.team?.name }}</div>
          </td>
          <td style="min-width:160px">
            <div *ngIf="u.role === 'EMPLOYEE'" class="util-bar-wrap">
              <div class="util-bar">
                <div class="util-bar-fill" [ngClass]="getUtilClass(u)" [style.width]="getUtilPct(u) + '%'"></div>
              </div>
              <span class="util-pct" [ngClass]="getUtilClass(u)">{{ getUtilPct(u) | number:'1.0-0' }}%</span>
            </div>
            <span *ngIf="u.role !== 'EMPLOYEE'" style="color:var(--text-muted);font-size:13px">—</span>
          </td>
          <td><span class="badge" [ngClass]="getStatusBadge(u.approvalStatus)">{{ u.approvalStatus }}</span></td>
          <td (click)="$event.stopPropagation()" style="white-space:nowrap">
            <span style="color:var(--text-muted);font-size:18px;margin-right:8px">›</span>
            <button *ngIf="auth.isDeptHead || auth.isPM" class="btn btn-icon btn-sm tl-primary" (click)="openTeamModal(u)" title="Assign Team">
              <span style="font-size:16px">👥</span>
            </button>
            <button *ngIf="auth.canManageProjects()" class="btn btn-icon btn-sm tl-danger" style="margin-left:6px" (click)="confirmDelete(u)" title="Remove user">✕</button>
          </td>
          </tr>
        </tbody>
      </table>
    </div>

    <!-- Pagination ... -->
  </div>
</div>

<!-- Assign Team Modal -->
<div class="modal-overlay" *ngIf="showTeamModal" (click)="showTeamModal = false">
  <div class="modal-card fade-in-up" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <div class="modal-title">Assign Team</div>
      <button class="btn-icon" (click)="showTeamModal = false">✕</button>
    </div>
    <div class="modal-body">
      <p style="margin-bottom:20px;color:var(--text-muted)">
        Select a team for <strong>{{ selectedUser?.firstName }} {{ selectedUser?.lastName }}</strong>.
      </p>

      <div class="form-group">
        <label class="form-label">Team</label>
        <select class="form-control" [(ngModel)]="targetTeamId">
          <option [value]="0">No Team (Unassigned)</option>
          <option *ngFor="let t of teams" [value]="t.id">{{ t.name }}</option>
        </select>
      </div>
    </div>
    <div class="modal-footer">
      <button class="btn btn-secondary" (click)="showTeamModal = false">Cancel</button>
      <button class="btn btn-primary" (click)="doAssignTeam()">Save Changes</button>
    </div>
  </div>
</div>

<app-confirm
  [show]="showDelConfirm"
  title="Remove User"
  [message]="'Remove ' + (selectedUser?.firstName || '') + ' ' + (selectedUser?.lastName || '') + ' from the system?'"
  (confirm)="doDelete()"
  (cancel)="showDelConfirm=false">
</app-confirm>
